/* global BigInt */
import { 
  Keypair, 
  SystemProgram, 
  Transaction,
  PublicKey,
  TransactionInstruction
} from '@solana/web3.js';

const TOKEN_PROGRAM_ID = new PublicKey('TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA');
const ASSOCIATED_TOKEN_PROGRAM_ID = new PublicKey('ATokenGPvbdGVxr1b2hvZbsiqW5xWH25efTNsLJA8knL');
const TOKEN_METADATA_PROGRAM_ID = new PublicKey('metaqbxxUerdq28cj1RbAWkYQm3ybzjb6a8bt518x1s');

const MINT_SIZE = 82;

// Helper functions for binary data
function writeUint32LE(value, buffer, offset) {
  buffer[offset] = value & 0xff;
  buffer[offset + 1] = (value >> 8) & 0xff;
  buffer[offset + 2] = (value >> 16) & 0xff;
  buffer[offset + 3] = (value >> 24) & 0xff;
}

function writeUint16LE(value, buffer, offset) {
  buffer[offset] = value & 0xff;
  buffer[offset + 1] = (value >> 8) & 0xff;
}

function writeBigUint64LE(value, buffer, offset) {
  const bigValue = BigInt.asUintN(64, BigInt(value));
  const low = Number(bigValue & BigInt(0xffffffff));
  const high = Number(bigValue >> BigInt(32));
  writeUint32LE(low, buffer, offset);
  writeUint32LE(high, buffer, offset + 4);
}

// Create InitializeMint instruction
function createInitializeMintInstruction(mint, decimals, mintAuthority, freezeAuthority) {
  const keys = [
    { pubkey: mint, isSigner: false, isWritable: true },
    { pubkey: SystemProgram.programId, isSigner: false, isWritable: false }
  ];

  const data = new Uint8Array(67);
  let offset = 0;

  data[offset++] = 0; // InitializeMint instruction
  data[offset++] = decimals;

  data.set(mintAuthority.toBytes(), offset);
  offset += 32;

  data[offset++] = freezeAuthority ? 1 : 0;
  if (freezeAuthority) {
    data.set(freezeAuthority.toBytes(), offset);
    offset += 32;
  }

  return {
    keys,
    programId: TOKEN_PROGRAM_ID,
    data: data.slice(0, offset)
  };
}

// Create Associated Token Account instruction
function createAssociatedTokenAccountInstruction(payer, associatedToken, owner, mint) {
  const keys = [
    { pubkey: payer, isSigner: true, isWritable: true },
    { pubkey: associatedToken, isSigner: false, isWritable: true },
    { pubkey: owner, isSigner: false, isWritable: false },
    { pubkey: mint, isSigner: false, isWritable: false },
    { pubkey: SystemProgram.programId, isSigner: false, isWritable: false },
    { pubkey: TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
    { pubkey: PublicKey.default, isSigner: false, isWritable: false }
  ];

  return {
    keys,
    programId: ASSOCIATED_TOKEN_PROGRAM_ID,
    data: new Uint8Array(0)
  };
}

// Create MintTo instruction
function createMintToInstruction(mint, destination, authority, amount) {
  const keys = [
    { pubkey: mint, isSigner: false, isWritable: true },
    { pubkey: destination, isSigner: false, isWritable: true },
    { pubkey: authority, isSigner: true, isWritable: false }
  ];

  const data = new Uint8Array(9);
  data[0] = 7; // MintTo instruction
  writeBigUint64LE(amount, data, 1);

  return {
    keys,
    programId: TOKEN_PROGRAM_ID,
    data
  };
}

// Create Metadata instruction (FIXED for Metaplex)
function createMetadataInstruction(mint, name, symbol, uri, payer, updateAuthority) {
  const [metadataPDA] = PublicKey.findProgramAddressSync(
    [new TextEncoder().encode('metadata'), TOKEN_METADATA_PROGRAM_ID.toBytes(), mint.toBytes()],
    TOKEN_METADATA_PROGRAM_ID
  );

  const nameBytes = new TextEncoder().encode(name);
  const symbolBytes = new TextEncoder().encode(symbol);
  const uriBytes = new TextEncoder().encode(uri);

  // Calculate data size
  let dataSize = 8; // discriminator
  dataSize += 4 + nameBytes.length;
  dataSize += 4 + symbolBytes.length;
  dataSize += 4 + uriBytes.length;
  dataSize += 2; // sellerFeeBasisPoints
  dataSize += 5; // 5 option flags

  const data = new Uint8Array(dataSize);
  let offset = 0;

  // Discriminator for CreateMetadataAccountV3
  const discriminator = new Uint8Array([33, 18, 37, 213, 20, 112, 118, 169]);
  data.set(discriminator, offset);
  offset += 8;

  // Write strings
  const writeString = (bytes) => {
    writeUint32LE(bytes.length, data, offset);
    offset += 4;
    data.set(bytes, offset);
    offset += bytes.length;
  };

  writeString(nameBytes);
  writeString(symbolBytes);
  writeString(uriBytes);

  // sellerFeeBasisPoints (u16) - 0 for fungible
  writeUint16LE(0, data, offset);
  offset += 2;

  // Option flags: creators, collection, uses, isMutable, collectionDetails
  data[offset++] = 0; // creators: None
  data[offset++] = 0; // collection: None
  data[offset++] = 0; // uses: None
  data[offset++] = 1; // isMutable: true
  data[offset++] = 0; // collectionDetails: None

  const keys = [
    { pubkey: metadataPDA, isSigner: false, isWritable: true },
    { pubkey: mint, isSigner: false, isWritable: false },
    { pubkey: payer, isSigner: true, isWritable: true },
    { pubkey: updateAuthority, isSigner: true, isWritable: false },
    { pubkey: SystemProgram.programId, isSigner: false, isWritable: false },
    { pubkey: PublicKey.default, isSigner: false, isWritable: false }
  ];

  return {
    keys,
    programId: TOKEN_METADATA_PROGRAM_ID,
    data: data.slice(0, offset)
  };
}

// Get Associated Token Address
async function getAssociatedTokenAddress(mint, owner) {
  const [address] = await PublicKey.findProgramAddress(
    [owner.toBytes(), TOKEN_PROGRAM_ID.toBytes(), mint.toBytes()],
    ASSOCIATED_TOKEN_PROGRAM_ID
  );
  return address;
}

// Main deploy function
export async function deployToken({ name, symbol, supply, decimals, description, imageUrl, wallet, connection, network, onLog }) {

  onLog(`Starting deployment: ${name} (${symbol})`);

  // Check balance
  const balance = await connection.getBalance(wallet.keypair.publicKey);
  if (balance < 0.01 * 1e9) {
    throw new Error('Insufficient SOL. Need at least 0.01 SOL.');
  }

  // Generate mint
  const mintKeypair = Keypair.generate();
  onLog(`Generated mint: ${mintKeypair.publicKey.toString().slice(0, 20)}...`);

  // Create metadata URI
  const metadataJson = {
    name,
    symbol,
    description: description || `${name} Token`,
    image: imageUrl || `https://placehold.co/400x400/00fff7/0a0e1a?text=${symbol}`,
    attributes: [],
    properties: {
      files: [{ uri: imageUrl || '', type: 'image/png' }],
      category: 'image',
      creators: [{ address: wallet.publicKey, share: 100 }]
    }
  };

  const metadataUri = `data:application/json;base64,${btoa(JSON.stringify(metadataJson))}`;
  onLog('Metadata prepared');

  // Get rent exemption
  const lamports = await connection.getMinimumBalanceForRentExemption(MINT_SIZE);
  onLog(`Rent exemption: ${lamports} lamports`);

  // Build transaction
  const transaction = new Transaction();

  // 1. Create mint account
  transaction.add(
    SystemProgram.createAccount({
      fromPubkey: wallet.keypair.publicKey,
      newAccountPubkey: mintKeypair.publicKey,
      space: MINT_SIZE,
      lamports,
      programId: TOKEN_PROGRAM_ID
    })
  );

  // 2. Initialize mint
  const initMintIx = createInitializeMintInstruction(
    mintKeypair.publicKey,
    parseInt(decimals),
    wallet.keypair.publicKey,
    wallet.keypair.publicKey
  );
  transaction.add(new TransactionInstruction(initMintIx));

  // 3. Create metadata
  const metadataIx = createMetadataInstruction(
    mintKeypair.publicKey,
    name,
    symbol,
    metadataUri,
    wallet.keypair.publicKey,
    wallet.keypair.publicKey
  );
  transaction.add(new TransactionInstruction(metadataIx));

  // 4. Create ATA
  const ata = await getAssociatedTokenAddress(mintKeypair.publicKey, wallet.keypair.publicKey);
  const ataIx = createAssociatedTokenAccountInstruction(
    wallet.keypair.publicKey,
    ata,
    wallet.keypair.publicKey,
    mintKeypair.publicKey
  );
  transaction.add(new TransactionInstruction(ataIx));

  // 5. Mint tokens
  const mintAmount = BigInt(supply) * BigInt(10 ** parseInt(decimals));
  const mintToIx = createMintToInstruction(
    mintKeypair.publicKey,
    ata,
    wallet.keypair.publicKey,
    mintAmount
  );
  transaction.add(new TransactionInstruction(mintToIx));

  // Send transaction
  transaction.feePayer = wallet.keypair.publicKey;
  const { blockhash } = await connection.getLatestBlockhash();
  transaction.recentBlockhash = blockhash;

  transaction.partialSign(mintKeypair);
  transaction.sign(wallet.keypair);

  onLog('Sending transaction...');
  const signature = await connection.sendRawTransaction(transaction.serialize());
  await connection.confirmTransaction(signature, 'confirmed');

  onLog(`✓ Token deployed!`, 'success');

  return {
    mint: mintKeypair.publicKey.toString(),
    signature,
    ata: ata.toString()
  };
}
